# Let's get context around each occurrence
def context(idx, window=80):
    start = max(0, idx - window)
    end = min(len(text), idx + window)
    return text[start:end].replace("\n", "\\n")

for phrase, idx, end in occurrences:
    print("PHRASE:", phrase)
    print("INDEX:", idx, end)
    print(context(idx))
    print("-----")

# Sort occurrences by index and build the output list
occurrences_sorted = sorted(occurrences, key=lambda x: x[1])

def classify(phrase):
    # a simple classification based on known lists
    hadeeths = {
        "المؤمن من سلم المسلمون من لسانه ويده",
        "المؤمن الذي يخالط الناس ويصبر على أذاهم أفضل من المؤمن الذي لا يخالط الناس ولا يصبر على أذاهم",
    }
    return "Hadeeth" if phrase in hadeeths else "Aya"

citations = []
for phrase, start, end in occurrences_sorted:
    citations.append({
        "span_start": start,
        "span_end": end,
        "span_text": phrase,
        "citation_type": classify(phrase)
    })

